        return *instancePtr;
    }

private:
    static std::unique_ptr<Singleton> instancePtr;
    static std::once_flag initFlag;
    Singleton() = default;
    ~Singleton() = default;
    Singleton(const Singleton&) = delete;
    Singleton& operator=(const Singleton&) = delete;
};
```

